## 四、HTTPS 配置（可选）

### 4.1 使用 Nginx 反向代理

在宿主机安装 Nginx，配置 SSL 证书后反向代理到 Docker 服务：

```nginx
server {
    listen 443 ssl http2;
    server_name your-domain.com;

    ssl_certificate     /etc/letsencrypt/live/your-domain.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/your-domain.com/privkey.pem;

    location / {
        proxy_pass http://127.0.0.1:28232;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}

/// <reference types="vite/client" />

declare module '*.vue' {
  import type { DefineComponent } from 'vue'
  const component: DefineComponent<{}, {}, any>
  export default component
}

server {
    listen       80;
    server_name  _;

    root /usr/share/nginx/html;
    index index.html;

    gzip on;
    gzip_types text/plain text/css application/json application/javascript text/xml application/xml application/xml+rss text/javascript image/svg+xml;
    gzip_min_length 256;

    # SPA fallback — serve index.html for all non-file, non-api routes.
    # No $uri/ (directory check) to avoid accidental 301 redirects.
    location / {
        try_files $uri /index.html;
    }

    # REST API — strip trailing slash to avoid Gin RedirectTrailingSlash loop,
    # then proxy with clean default settings.
    location /api/ {
        rewrite ^/api/(.*)/$ /api/$1 break;
        proxy_pass http://backend:28131;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_connect_timeout 60s;
        proxy_send_timeout    300s;
        proxy_read_timeout    300s;
    }

    # SSE streaming — custom location prefix so nginx never confuses it with REST.
    # The rewrite inside /api/ does NOT affect this block (regex takes priority).
    location ~ ^/api/v1/tasks/[^/]+/stream$ {
        proxy_pass http://backend:28131;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_http_version 1.1;
        proxy_set_header Connection "";
        proxy_buffering off;
        proxy_cache off;
        proxy_connect_timeout 60s;
        proxy_send_timeout    86400s;
        proxy_read_timeout    86400s;
    }

    location /healthz {
        proxy_pass http://backend:28131;
    }

    error_page 500 502 503 504 /50x.html;
    location = /50x.html {
        root /usr/share/nginx/html;
    }
}

