			}
			g.StartNodeID = n.ID
		}
	}
	if g.StartNodeID == "" {
		return nil, fmt.Errorf("missing start node")
	}
	for _, e := range edges {
		g.Preds[e.Target] = append(g.Preds[e.Target], e.Source)
