func toUUIDSlice(v any) []uuid.UUID {
	arr, ok := v.([]any)
	if !ok {
		// Try string slice
		if sarr, ok := v.([]string); ok {
			var out []uuid.UUID
			for _, s := range sarr {
				id := uuidFromAny(s)
				if id != uuid.Nil {
					out = append(out, id)
				}
			}
			return out
		}
		return nil
	}
	var out []uuid.UUID
	for _, it := range arr {
		id := uuidFromAny(it)
		if id != uuid.Nil {
			out = append(out, id)
		}
	}
	return out
}

