func consensus(m map[string]string) bool {
	if len(m) == 0 {
		return false
	}
	var first string
	for _, v := range m {
		first = strings.TrimSpace(v)
		break
	}
	for _, v := range m {
		if strings.TrimSpace(v) != first {
			return false
		}
	}
	return true
}

